8901 // Adjust the recipes for reductions. For in-loop reductions the chain of
8902 // instructions leading from the loop exit instr to the phi need to be converted
8903 // to reductions, with one operand being vector and the other being the scalar
8904 // reduction chain. For other reductions, a select is introduced between the phi
8905 // and live-out recipes when folding the tail.
8906 //
8907 // A ComputeReductionResult recipe is added to the middle block, also for
8908 // in-loop reductions which compute their result in-loop, because generating
8909 // the subsequent bc.merge.rdx phi is driven by ComputeReductionResult recipes.
8910 void LoopVectorizationPlanner::adjustRecipesForReductions(
8911     VPBasicBlock *LatchVPBB, VPlanPtr &Plan, VPRecipeBuilder &RecipeBuilder,
8912     ElementCount MinVF) {
8913   VPRegionBlock *VectorLoopRegion = Plan->getVectorLoopRegion();
8914   VPBasicBlock *Header = VectorLoopRegion->getEntryBasicBlock();
8915   // Gather all VPReductionPHIRecipe and sort them so that Intermediate stores
8916   // sank outside of the loop would keep the same order as they had in the
8917   // original loop.
8918   SmallVector<VPReductionPHIRecipe *> ReductionPHIList;
8919   for (VPRecipeBase &R : Header->phis()) {
8920     if (auto *ReductionPhi = dyn_cast<VPReductionPHIRecipe>(&R))
8921       ReductionPHIList.emplace_back(ReductionPhi);
8922   }
8923   bool HasIntermediateStore = false;
8924   stable_sort(ReductionPHIList,
8925               [this, &HasIntermediateStore](const VPReductionPHIRecipe *R1,
8926                                             const VPReductionPHIRecipe *R2) {
8927                 auto *IS1 = R1->getRecurrenceDescriptor().IntermediateStore;
8928                 auto *IS2 = R2->getRecurrenceDescriptor().IntermediateStore;
8929                 HasIntermediateStore |= IS1 || IS2;
8930 
8931                 // If neither of the recipes has an intermediate store, keep the
8932                 // order the same.
8933                 if (!IS1 && !IS2)
8934                   return false;
8935 
8936                 // If only one of the recipes has an intermediate store, then
8937                 // move it towards the beginning of the list.
8938                 if (IS1 && !IS2)
8939                   return true;
8940 
8941                 if (!IS1 && IS2)
8942                   return false;
8943 
8944                 // If both recipes have an intermediate store, then the recipe
8945                 // with the later store should be processed earlier. So it
8946                 // should go to the beginning of the list.
8947                 return DT->dominates(IS2, IS1);
8948               });
8949 
8950   if (HasIntermediateStore && ReductionPHIList.size() > 1)
8951     for (VPRecipeBase *R : ReductionPHIList)
8952       R->moveBefore(*Header, Header->getFirstNonPhi());
8953 
8954   for (VPRecipeBase &R : Header->phis()) {
8955     auto *PhiR = dyn_cast<VPReductionPHIRecipe>(&R);
8956     if (!PhiR || !PhiR->isInLoop() || (MinVF.isScalar() && !PhiR->isOrdered()))
8957       continue;
8958 
8959     const RecurrenceDescriptor &RdxDesc = PhiR->getRecurrenceDescriptor();
8960     RecurKind Kind = RdxDesc.getRecurrenceKind();
8961     assert(!RecurrenceDescriptor::isAnyOfRecurrenceKind(Kind) &&
8962            "AnyOf reductions are not allowed for in-loop reductions");
8963 
8964     // Collect the chain of "link" recipes for the reduction starting at PhiR.
8965     SetVector<VPSingleDefRecipe *> Worklist;
8966     Worklist.insert(PhiR);
8967     for (unsigned I = 0; I != Worklist.size(); ++I) {
8968       VPSingleDefRecipe *Cur = Worklist[I];
8969       for (VPUser *U : Cur->users()) {
8970         auto *UserRecipe = dyn_cast<VPSingleDefRecipe>(U);
8971         if (!UserRecipe) {
8972           assert(isa<VPLiveOut>(U) &&
8973                  "U must either be a VPSingleDef or VPLiveOut");
8974           continue;
8975         }
8976         Worklist.insert(UserRecipe);
8977       }
8978     }
8979 
8980     // Visit operation "Links" along the reduction chain top-down starting from
8981     // the phi until LoopExitValue. We keep track of the previous item
8982     // (PreviousLink) to tell which of the two operands of a Link will remain
8983     // scalar and which will be reduced. For minmax by select(cmp), Link will be
8984     // the select instructions. Blend recipes of in-loop reduction phi's  will
8985     // get folded to their non-phi operand, as the reduction recipe handles the
8986     // condition directly.
8987     VPSingleDefRecipe *PreviousLink = PhiR; // Aka Worklist[0].
8988     for (VPSingleDefRecipe *CurrentLink : Worklist.getArrayRef().drop_front()) {
8989       Instruction *CurrentLinkI = CurrentLink->getUnderlyingInstr();
8990 
8991       // Index of the first operand which holds a non-mask vector operand.
8992       unsigned IndexOfFirstOperand;
8993       // Recognize a call to the llvm.fmuladd intrinsic.
8994       bool IsFMulAdd = (Kind == RecurKind::FMulAdd);
8995       VPValue *VecOp;
8996       VPBasicBlock *LinkVPBB = CurrentLink->getParent();
8997       if (IsFMulAdd) {
8998         assert(
8999             RecurrenceDescriptor::isFMulAddIntrinsic(CurrentLinkI) &&
9000             "Expected instruction to be a call to the llvm.fmuladd intrinsic");
9001         assert(((MinVF.isScalar() && isa<VPReplicateRecipe>(CurrentLink)) ||
9002                 isa<VPWidenCallRecipe>(CurrentLink)) &&
9003                CurrentLink->getOperand(2) == PreviousLink &&
9004                "expected a call where the previous link is the added operand");
9005 
9006         // If the instruction is a call to the llvm.fmuladd intrinsic then we
9007         // need to create an fmul recipe (multiplying the first two operands of
9008         // the fmuladd together) to use as the vector operand for the fadd
9009         // reduction.
9010         VPInstruction *FMulRecipe = new VPInstruction(
9011             Instruction::FMul,
9012             {CurrentLink->getOperand(0), CurrentLink->getOperand(1)},
9013             CurrentLinkI->getFastMathFlags());
9014         LinkVPBB->insert(FMulRecipe, CurrentLink->getIterator());
9015         VecOp = FMulRecipe;
9016       } else {
9017         auto *Blend = dyn_cast<VPBlendRecipe>(CurrentLink);
9018         if (PhiR->isInLoop() && Blend) {
9019           assert(Blend->getNumIncomingValues() == 2 &&
9020                  "Blend must have 2 incoming values");
9021           if (Blend->getIncomingValue(0) == PhiR)
9022             Blend->replaceAllUsesWith(Blend->getIncomingValue(1));
9023           else {
9024             assert(Blend->getIncomingValue(1) == PhiR &&
9025                    "PhiR must be an operand of the blend");
9026             Blend->replaceAllUsesWith(Blend->getIncomingValue(0));
9027           }
9028           continue;
