8982     // (PreviousLink) to tell which of the two operands of a Link will remain
8983     // scalar and which will be reduced. For minmax by select(cmp), Link will be
8984     // the select instructions. Blend recipes of in-loop reduction phi's  will
8985     // get folded to their non-phi operand, as the reduction recipe handles the
8986     // condition directly.
8987     VPSingleDefRecipe *PreviousLink = PhiR; // Aka Worklist[0].
8988     for (VPSingleDefRecipe *CurrentLink : Worklist.getArrayRef().drop_front()) {
8989       Instruction *CurrentLinkI = CurrentLink->getUnderlyingInstr();
