8901 // Adjust the recipes for reductions. For in-loop reductions the chain of
8902 // instructions leading from the loop exit instr to the phi need to be converted
8903 // to reductions, with one operand being vector and the other being the scalar
8904 // reduction chain. For other reductions, a select is introduced between the phi
8905 // and live-out recipes when folding the tail.
8906 //
8907 // A ComputeReductionResult recipe is added to the middle block, also for
8908 // in-loop reductions which compute their result in-loop, because generating
8909 // the subsequent bc.merge.rdx phi is driven by ComputeReductionResult recipes.
8910 void LoopVectorizationPlanner::adjustRecipesForReductions(
8911     VPBasicBlock *LatchVPBB, VPlanPtr &Plan, VPRecipeBuilder &RecipeBuilder,
8912     ElementCount MinVF) {
8913   VPRegionBlock *VectorLoopRegion = Plan->getVectorLoopRegion();
8914   VPBasicBlock *Header = VectorLoopRegion->getEntryBasicBlock();
8915   // Gather all VPReductionPHIRecipe and sort them so that Intermediate stores
8916   // sank outside of the loop would keep the same order as they had in the
8917   // original loop.
8918   SmallVector<VPReductionPHIRecipe *> ReductionPHIList;
8919   for (VPRecipeBase &R : Header->phis()) {
8920     if (auto *ReductionPhi = dyn_cast<VPReductionPHIRecipe>(&R))
8921       ReductionPHIList.emplace_back(ReductionPhi);
8922   }
8923   bool HasIntermediateStore = false;
8924   stable_sort(ReductionPHIList,
8925               [this, &HasIntermediateStore](const VPReductionPHIRecipe *R1,
8926                                             const VPReductionPHIRecipe *R2) {
8927                 auto *IS1 = R1->getRecurrenceDescriptor().IntermediateStore;
8928                 auto *IS2 = R2->getRecurrenceDescriptor().IntermediateStore;
8929                 HasIntermediateStore |= IS1 || IS2;
8930 
8931                 // If neither of the recipes has an intermediate store, keep the
8932                 // order the same.
8933                 if (!IS1 && !IS2)
8934                   return false;
8935 
8936                 // If only one of the recipes has an intermediate store, then
8937                 // move it towards the beginning of the list.
8938                 if (IS1 && !IS2)
8939                   return true;
8940 
8941                 if (!IS1 && IS2)
8942                   return false;
8943 
8944                 // If both recipes have an intermediate store, then the recipe
8945                 // with the later store should be processed earlier. So it
8946                 // should go to the beginning of the list.
8947                 return DT->dominates(IS2, IS1);
8948               });
